prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?task ?taskName ?participantName WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "0cad2ceffcad428aab5664a733b078e6" ;
         tai:belongsTo ?org .

  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?model .

  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo ;
        bbo:name ?taskName .

  ?task bboExt:initiatingParticipantRef ?partRef .

  ?participant a bboExt:Participant ;
               tai:belongsTo ?choreo ;
               bbo:name ?participantName .

  FILTER(
    STRENDS(STR(?participant), ?partRef)
  )

  FILTER(CONTAINS(LCASE(STR(?participantName)), LCASE("obavestavanje studenta")))
}
ORDER BY ?taskName
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?task ?taskName ?participantName ?partRef WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "0cad2ceffcad428aab5664a733b078e6" ;
         tai:belongsTo ?org .

  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?model .

  ?participant a bboExt:Participant ;
               tai:belongsTo ?choreo ;
               bbo:name ?participantName .

  FILTER(
    CONTAINS(LCASE(STR(?participantName)), LCASE("obavestavanje")) ||
    CONTAINS(LCASE(STR(?participantName)), LCASE("studenta"))
  )

  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo ;
        bbo:name ?taskName ;
        bboExt:initiatingParticipantRef ?partRef .

  FILTER(STRENDS(STR(?participant), ?partRef))
}
ORDER BY ?taskName
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?participant ?participantName ?choreo WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "0cad2ceffcad428aab5664a733b078e6" ;
         tai:belongsTo ?org .

  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?model .

  ?participant a bboExt:Participant ;
               tai:belongsTo ?choreo .

  OPTIONAL { ?participant bbo:name ?participantName . }

  FILTER(
    !BOUND(?participantName) ||
    CONTAINS(LCASE(STR(COALESCE(?participantName, ""))), LCASE("obavestavanje")) ||
    CONTAINS(LCASE(STR(COALESCE(?participantName, ""))), LCASE("studenta"))
  )
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?prop (COUNT(*) AS ?count) WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "0cad2ceffcad428aab5664a733b078e6" ;
         tai:belongsTo ?org .

  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?model .

  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo .

  ?task ?prop ?value .

  FILTER(STRSTARTS(STR(?prop), "http://www.onto-bpo.eu/ontologies/bboExtension#") ||
          STRSTARTS(STR(?prop), "http://www.onto-bpo.eu/ontologies/bbo#"))
}
GROUP BY ?prop
ORDER BY DESC(?count)
LIMIT 25

