prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?normId ?origId ?created WHERE {
  ?model a bboExt:Model ;
         tai:belongsTo ?org .
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:normalizedId ?normId . }
  OPTIONAL { ?model tai:originalId ?origId . }
  OPTIONAL { ?model tai:modelCreated ?created . }

  FILTER(
    CONTAINS(STR(?normId), "0cad2ceffcad428aab5664a733b078e6") ||
    CONTAINS(STR(?origId), "0cad2ceffcad428aab5664a733b078e6") ||
    CONTAINS(STR(?model), "0cad2ceffcad428aab5664a733b078e6")
  )
}
ORDER BY DESC(?created)
LIMIT 25

